5471             TTI.getShuffleCost(TTI::SK_PermuteSingleSrc, Shuffle->getType(),
5472                                OldLoadTy, OldMask, CostKind);
5473         NewCost +=
5474             TTI.getShuffleCost(TTI::SK_PermuteSingleSrc, Shuffle->getType(),
5475                                NewLoadTy, NewMask, CostKind);
5476       }
