5518 // Attempt to narrow a phi of shufflevector instructions where the two incoming
5519 // values have the same operands but different masks. If the two shuffle masks
5520 // are offsets of one another we can use one branch to rotate the incoming
5521 // vector and perform one larger shuffle after the phi.
5522 bool VectorCombine::shrinkPhiOfShuffles(Instruction &I) {
5523   auto *Phi = dyn_cast<PHINode>(&I);
5524   if (!Phi || Phi->getNumIncomingValues() != 2u)
5525     return false;
5526 
5527   Value *Op = nullptr;
5528   ArrayRef<int> Mask0;
5529   ArrayRef<int> Mask1;
5530 
5531   if (!match(Phi->getOperand(0u),
5532              m_OneUse(m_Shuffle(m_Value(Op), m_Poison(), m_Mask(Mask0)))) ||
5533       !match(Phi->getOperand(1u),
5534              m_OneUse(m_Shuffle(m_Specific(Op), m_Poison(), m_Mask(Mask1)))))
5535     return false;
5536 
5537   auto *Shuf = cast<ShuffleVectorInst>(Phi->getOperand(0u));
5538 
5539   // Ensure result vectors are wider than the argument vector.
5540   auto *InputVT = cast<FixedVectorType>(Op->getType());
5541   auto *ResultVT = cast<FixedVectorType>(Shuf->getType());
5542   auto const InputNumElements = InputVT->getNumElements();
5543 
5544   if (InputNumElements >= ResultVT->getNumElements())
5545     return false;
5546 
5547   // Take the difference of the two shuffle masks at each index. Ignore poison
5548   // values at the same index in both masks.
5549   SmallVector<int, 16> NewMask;
5550   NewMask.reserve(Mask0.size());
5551 
5552   for (auto [M0, M1] : zip(Mask0, Mask1)) {
5553     if (M0 >= 0 && M1 >= 0)
5554       NewMask.push_back(M0 - M1);
5555     else if (M0 == -1 && M1 == -1)
5556       continue;
5557     else
5558       return false;
5559   }
5560 
5561   // Ensure all elements of the new mask are equal. If the difference between
5562   // the incoming mask elements is the same, the two must be constant offsets
5563   // of one another.
5564   if (NewMask.empty() || !all_equal(NewMask))
5565     return false;
5566 
5567   // Create new mask using difference of the two incoming masks.
5568   int MaskOffset = NewMask[0u];
5569   unsigned Index = (InputNumElements + MaskOffset) % InputNumElements;
5570   NewMask.clear();
5571 
5572   for (unsigned I = 0u; I < InputNumElements; ++I) {
5573     NewMask.push_back(Index);
5574     Index = (Index + 1u) % InputNumElements;
5575   }
5576 
5577   // Calculate costs for worst cases and compare.
5578   auto const Kind = TTI::SK_PermuteSingleSrc;
5579   auto OldCost =
5580       std::max(TTI.getShuffleCost(Kind, ResultVT, InputVT, Mask0, CostKind),
5581                TTI.getShuffleCost(Kind, ResultVT, InputVT, Mask1, CostKind));
5582   auto NewCost = TTI.getShuffleCost(Kind, InputVT, InputVT, NewMask, CostKind) +
5583                  TTI.getShuffleCost(Kind, ResultVT, InputVT, Mask1, CostKind);
5584 
5585   LLVM_DEBUG(dbgs() << "Found a phi of mergeable shuffles: " << I
5586                     << "\n  OldCost: " << OldCost << " vs NewCost: " << NewCost
5587                     << "\n");
5588 
5589   if (NewCost > OldCost)
5590     return false;
5591 
5592   // Create new shuffles and narrowed phi.
5593   auto Builder = IRBuilder(Shuf);
5594   Builder.SetCurrentDebugLocation(Shuf->getDebugLoc());
5595   auto *PoisonVal = PoisonValue::get(InputVT);
5596   auto *NewShuf0 = Builder.CreateShuffleVector(Op, PoisonVal, NewMask);
5597   Worklist.push(cast<Instruction>(NewShuf0));
5598 
5599   Builder.SetInsertPoint(Phi);
5600   Builder.SetCurrentDebugLocation(Phi->getDebugLoc());
5601   auto *NewPhi = Builder.CreatePHI(NewShuf0->getType(), 2u);
5602   NewPhi->addIncoming(NewShuf0, Phi->getIncomingBlock(0u));
5603   NewPhi->addIncoming(Op, Phi->getIncomingBlock(1u));
5604 
5605   Builder.SetInsertPoint(*NewPhi->getInsertionPointAfterDef());
5606   PoisonVal = PoisonValue::get(NewPhi->getType());
5607   auto *NewShuf1 = Builder.CreateShuffleVector(NewPhi, PoisonVal, Mask1);
5608 
5609   replaceValue(*Phi, *NewShuf1);
5610   return true;
5611 }
